#!/usr/bin/env python3
"""
build_profile.py — regenerates assets/profile.svg with live GitHub stats.
Runs locally or in GitHub Actions. No third-party packages, no external logo
fetches: everything is embedded. Stdlib only.

Usage:  python build_profile.py [github_username]
Default username: ChurchillonData
"""
import sys, os, json, urllib.request, datetime
from collections import Counter

USERNAME = sys.argv[1] if len(sys.argv) > 1 else "ChurchillonData"
OUT_PATH = os.path.join("profile.svg")

# ----- palette -----
PAPER="#F4F2EE"; INK="#1A1A1A"; ORANGE="#FF4A1C"; GREY="#6B6B6B"; RULE="#D8D4CC"
HEAD="<style>.hel{font-family:\'Helvetica Neue\',Helvetica,Arial,sans-serif;}.mono{font-family:\'SFMono-Regular\',Consolas,\'Liberation Mono\',monospace;}</style>"

# ----- embedded logos (base64 data URIs) -----
LOGOS = json.loads(r'''{"Python": "data:image/svg+xml;base64,", "R": "data:image/svg+xml;base64,", "SQL": "data:image/svg+xml;base64,", "TensorFlow": "data:image/svg+xml;base64,", "PyTorch": "data:image/svg+xml;base64,", "scikit-learn": "data:image/svg+xml;base64,", "Pandas": "data:image/svg+xml;base64,", "NumPy": "data:image/svg+xml;base64,", "Tableau": "data:image/svg+xml;base64,", "Power BI": "data:image/svg+xml;base64,", "Plotly": "data:image/svg+xml;base64,", "Matplotlib": "data:image/svg+xml;base64,", "Jupyter": "data:image/svg+xml;base64,", "AWS": "data:image/svg+xml;base64,", "Docker": "data:image/svg+xml;base64,", "Git": "data:image/svg+xml;base64,"}''')

# ----- fetch live stats -----
def api(path):
    req = urllib.request.Request(
        "https://api.github.com/" + path,
        headers={"User-Agent": "profile-builder", "Accept": "application/vnd.github+json"})
    tok = os.environ.get("GITHUB_TOKEN")
    if tok:
        req.add_header("Authorization", "Bearer " + tok)
    with urllib.request.urlopen(req, timeout=30) as r:
        return json.load(r)

def fetch_stats(user):
    u = api("users/" + user)
    repos = []
    page = 1
    while page <= 5:
        batch = api(f"users/{user}/repos?per_page=100&page={page}&sort=updated")
        if not isinstance(batch, list) or not batch:
            break
        repos.extend(batch)
        if len(batch) < 100:
            break
        page += 1

    own = [r for r in repos if not r.get("fork")]
    langs = Counter()
    for r in repos:
        if r.get("language"):
            langs[r["language"]] += 1

    # months on GitHub
    created = datetime.datetime.strptime(u["created_at"], "%Y-%m-%dT%H:%M:%SZ")
    now = datetime.datetime.utcnow()
    months = (now.year - created.year) * 12 + (now.month - created.month)
    months = max(months, 1)

    pct_original = round(100 * len(own) / len(repos)) if repos else 100

    return {
        "public_repos": u.get("public_repos", len(repos)),
        "followers": u.get("followers", 0),
        "months": months,
        "pct_original": pct_original,
        "langs": langs,
        "total_repos": len(repos),
    }

# ----- SVG drawing -----
def esc(s):
    return s.replace("&", "&amp;").replace("<", "&lt;").replace(">", "&gt;")

def build_svg(s):
    W = 1200
    parts = []
    y = 0
    def line(x1, yy, x2, w=1, color=RULE):
        return f'<line x1="{x1}" y1="{yy}" x2="{x2}" y2="{yy}" stroke="{color}" stroke-width="{w}"/>'

    # ===== HERO =====
    parts.append(f'<text x="64" y="{y+40}" class="mono" font-size="12" letter-spacing="3" fill="{INK}">PORTFOLIO / {datetime.datetime.utcnow().year}</text>')
    parts.append(f'<text x="1136" y="{y+40}" text-anchor="end" class="mono" font-size="12" letter-spacing="3" fill="{INK}">ACCRA &#8594; LONDON</text>')
    parts.append(line(64, y+52, 1136, 1, INK))
    parts.append(f'<line x1="64" y1="{y+52}" x2="64" y2="{y+410}" stroke="{INK}" stroke-width="2"/>')
    parts.append(f'<line x1="820" y1="{y+52}" x2="820" y2="{y+410}" stroke="{RULE}" stroke-width="1"/>')
    parts.append(f'<text x="92" y="{y+84}" class="mono" font-size="13" letter-spacing="4" fill="{ORANGE}">DATA SCIENCE</text>')
    parts.append(f'<text x="1150" y="{y+238}" text-anchor="end" class="hel" font-size="240" font-weight="700" fill="{ORANGE}" opacity="0.10" letter-spacing="-8">01</text>')
    parts.append(f'<text x="60" y="{y+220}" class="hel" font-size="132" font-weight="700" fill="{INK}" letter-spacing="-3">Emmanuel</text>')
    parts.append(f'<text x="60" y="{y+344}" class="hel" font-size="132" font-weight="700" fill="{INK}" letter-spacing="-3">Boakye<tspan fill="{ORANGE}">.</tspan></text>')
    parts.append(f'<text x="836" y="{y+138}" class="hel" font-size="22" font-weight="500" fill="{INK}">Data Scientist</text>')
    parts.append(f'<text x="836" y="{y+170}" class="hel" font-size="22" font-weight="500" fill="{GREY}">Machine Learning Engineer</text>')
    parts.append(f'<text x="836" y="{y+202}" class="hel" font-size="22" font-weight="500" fill="{GREY}">AI Engineer</text>')
    for i, t in enumerate(["MSc Data Science &amp; AI. I build", "explainable ML systems and turn", "messy data into decisions."]):
        parts.append(f'<text x="836" y="{y+258+i*22}" class="hel" font-size="15" fill="#3A3A3A">{t}</text>')
    parts.append(f'<rect x="64" y="{y+374}" width="120" height="10" fill="{ORANGE}"/>')
    parts.append(line(64, y+428, 1136, 1, INK))
    parts.append(f'<text x="64" y="{y+450}" class="mono" font-size="12" letter-spacing="2" fill="{INK}">001 — INTRO</text>')
    parts.append(f'<text x="600" y="{y+450}" text-anchor="middle" class="mono" font-size="12" letter-spacing="2" fill="{INK}">EST. UK</text>')
    parts.append(f'<text x="1136" y="{y+450}" text-anchor="end" class="mono" font-size="12" letter-spacing="2" fill="{INK}">SCROLL &#8595;</text>')
    y += 470

    def section_header(num, kicker, title):
        nonlocal y
        parts.append(line(64, y+40, 1136, 2, INK))
        parts.append(f'<text x="64" y="{y+32}" class="mono" font-size="12" letter-spacing="3" fill="{ORANGE}">{kicker}</text>')
        parts.append(f'<text x="1136" y="{y+32}" text-anchor="end" class="mono" font-size="12" letter-spacing="3" fill="{INK}">SECTION / {num}</text>')
        parts.append(f'<text x="60" y="{y+104}" class="hel" font-size="52" font-weight="700" fill="{INK}" letter-spacing="-2">{title}</text>')
        parts.append(f'<text x="1140" y="{y+122}" text-anchor="end" class="hel" font-size="100" font-weight="700" fill="{ORANGE}" opacity="0.12" letter-spacing="-4">{num}</text>')
        y += 140

    # ===== ABOUT =====
    section_header("02", "PROFILE", "About")
    ay = y
    parts.append(f'<line x1="600" y1="{ay}" x2="600" y2="{ay+250}" stroke="{RULE}" stroke-width="1"/>')
    parts.append(f'<text x="60" y="{ay+10}" class="mono" font-size="12" letter-spacing="3" fill="{ORANGE}">01 / WHO</text>')
    about_left = ["Insights from", "messy data,", "BUILT", "themselves."]
    for i, t in enumerate(about_left):
        if t == "BUILT":
            parts.append(f'<text x="58" y="{ay+76+i*48}" class="hel" font-size="40" font-weight="700" fill="{INK}" letter-spacing="-1.5">built to <tspan fill="{ORANGE}">explain</tspan></text>')
        else:
            parts.append(f'<text x="58" y="{ay+76+i*48}" class="hel" font-size="40" font-weight="700" fill="{INK}" letter-spacing="-1.5">{t}</text>')
    parts.append(f'<text x="636" y="{ay+10}" class="mono" font-size="12" letter-spacing="3" fill="{INK}">02 / WHAT</text>')
    body1 = ["Data Scientist and MSc graduate in Data", "Science &amp; AI. I work across analytics,", "machine learning, business intelligence,", "and AI-powered automation."]
    for i, t in enumerate(body1):
        parts.append(f'<text x="636" y="{ay+72+i*28}" class="hel" font-size="17" fill="{INK}">{t}</text>')
    body2 = ["Predictive modeling and intelligent systems", "that turn data into decisions across industries."]
    for i, t in enumerate(body2):
        parts.append(f'<text x="636" y="{ay+198+i*28}" class="hel" font-size="17" fill="{GREY}">{t}</text>')
    y += 270

    # ===== FOCUS =====
    section_header("03", "FOCUS", "What I Work On")
    fy = y
    def fcol(x, num, title, lines):
        parts.append(f'<text x="{x}" y="{fy+40}" class="hel" font-size="56" font-weight="700" fill="{ORANGE}" opacity="0.25" letter-spacing="-2">{num}</text>')
        parts.append(f'<text x="{x+2}" y="{fy+92}" class="hel" font-size="22" font-weight="700" fill="{INK}">{title}</text>')
        parts.append(f'<line x1="{x+2}" y1="{fy+106}" x2="{x+300}" y2="{fy+106}" stroke="{INK}" stroke-width="1.5"/>')
        yy = fy + 138
        for ln in lines:
            parts.append(f'<text x="{x+2}" y="{yy}" class="hel" font-size="15" fill="{GREY}">{ln}</text>'); yy += 28
    fcol(64, "01", "Build", ["Explainable ML systems", "Predictive models", "AI workflow automation"])
    fcol(450, "02", "Explore", ["Deep learning", "MLOps", "Applied AI research"])
    fcol(836, "03", "Collaborate", ["Open-source", "Hackathons", "Consulting", "Tech communities"])
    parts.append(f'<line x1="418" y1="{fy}" x2="418" y2="{fy+250}" stroke="{RULE}" stroke-width="1"/>')
    parts.append(f'<line x1="804" y1="{fy}" x2="804" y2="{fy+250}" stroke="{RULE}" stroke-width="1"/>')
    y += 270

    # ===== STACK =====
    section_header("04", "TOOLING", "Stack")
    ROWS = [("LANGUAGES", ["Python", "R", "SQL"]),
            ("ML / AI", ["TensorFlow", "PyTorch", "scikit-learn", "Pandas", "NumPy"]),
            ("VIZ / BI", ["Tableau", "Power BI", "Plotly", "Matplotlib"]),
            ("DEV / CLOUD", ["Jupyter", "AWS", "Docker", "Git"])]
    row_h = 92
    sy = y
    parts.append(line(64, sy, 1136, 2, INK))
    for i, (cat, items) in enumerate(ROWS):
        ry = sy + i*row_h
        if i > 0:
            parts.append(line(64, ry, 1136, 1, RULE))
        parts.append(f'<text x="64" y="{ry+52}" class="mono" font-size="13" letter-spacing="2" fill="{ORANGE}">{cat}</text>')
        x = 340
        for label in items:
            parts.append(f'<image x="{x}" y="{ry+24}" width="28" height="28" xlink:href="{LOGOS[label]}"/>')
            parts.append(f'<text x="{x-2}" y="{ry+76}" class="hel" font-size="12" fill="{INK}">{label}</text>')
            x += 150
    parts.append(line(64, sy+len(ROWS)*row_h, 1136, 2, INK))
    y += len(ROWS)*row_h + 30

    # ===== ACTIVITY (live) =====
    section_header("05", "METRICS", "Activity")
    ry = y
    STATS = [(str(s["public_repos"]), "PUBLIC REPOSITORIES"),
             (str(s["followers"]), "FOLLOWERS"),
             (str(s["months"]), "MONTHS ON GITHUB"),
             (str(s["pct_original"]) + "%", "ORIGINAL WORK")]
    colw = (1136 - 64) // 4
    for i, (num, label) in enumerate(STATS):
        cx = 64 + i*colw
        numcol = ORANGE if i == 3 else INK
        parts.append(f'<text x="{cx}" y="{ry+70}" class="hel" font-size="76" font-weight="700" fill="{numcol}" letter-spacing="-3">{num}</text>')
        parts.append(f'<text x="{cx+2}" y="{ry+98}" class="mono" font-size="11" letter-spacing="2" fill="{GREY}">{label}</text>')
        if i > 0:
            parts.append(f'<line x1="{cx-20}" y1="{ry+20}" x2="{cx-20}" y2="{ry+100}" stroke="{RULE}" stroke-width="1"/>')

    # language distribution (live, top 4 + Other)
    by = ry + 150
    parts.append(f'<text x="64" y="{by-14}" class="mono" font-size="12" letter-spacing="2" fill="{ORANGE}">LANGUAGE DISTRIBUTION</text>')
    parts.append(f'<text x="1136" y="{by-14}" text-anchor="end" class="mono" font-size="11" letter-spacing="1" fill="{GREY}">BY REPOSITORY</text>')
    palette = [INK, ORANGE, "#8A8A8A", "#B0B0B0"]
    top = s["langs"].most_common(4)
    named_total = sum(v for _, v in top)
    other = max(s["total_repos"] - named_total, 0)
    segments = [(n, v, palette[i]) for i, (n, v) in enumerate(top)]
    if other > 0:
        segments.append(("Other", other, RULE))
    total = sum(v for _, v, _ in segments) or 1
    barW = 1072; barX = 64; barH = 18
    x = barX
    for name, v, col in segments:
        w = barW * v / total
        parts.append(f'<rect x="{x:.1f}" y="{by}" width="{w:.1f}" height="{barH}" fill="{col}"/>')
        x += w
    ly = by + 48
    x = barX
    for name, v, col in segments:
        pct = round(100 * v / total)
        parts.append(f'<rect x="{x}" y="{ly-10}" width="11" height="11" fill="{col}"/>')
        parts.append(f'<text x="{x+18}" y="{ly}" class="hel" font-size="13" fill="{INK}">{esc(name)}</text>')
        parts.append(f'<text x="{x+18}" y="{ly+18}" class="mono" font-size="11" fill="{GREY}">{pct}%</text>')
        x += 210
    parts.append(line(64, by+90, 1136, 1, RULE))
    y = by + 120

    # ===== CONTACT / FOOTER =====
    section_header("06", "CONTACT", "Get In Touch")
    fy = y; FH = 200
    parts.append(f'<rect x="0" y="{fy}" width="{W}" height="{FH}" fill="{INK}"/>')
    parts.append(f'<rect x="64" y="{fy+40}" width="1072" height="3" fill="{ORANGE}"/>')
    parts.append(f'<text x="64" y="{fy+32}" class="mono" font-size="12" letter-spacing="3" fill="{ORANGE}">AVAILABLE FOR WORK</text>')
    parts.append(f'<text x="60" y="{fy+120}" class="hel" font-size="56" font-weight="700" fill="{PAPER}" letter-spacing="-2">Let&#8217;s build something.</text>')
    parts.append(f'<text x="64" y="{fy+170}" class="mono" font-size="14" fill="{PAPER}">boakyemmanuel1@outlook.com</text>')
    parts.append(f'<text x="1136" y="{fy+170}" text-anchor="end" class="mono" font-size="14" fill="#9A9A9A">linkedin.com/in/emmanuel-boakye-gh</text>')
    parts.append(f'<text x="600" y="{fy+196}" text-anchor="middle" class="hel" font-size="12" font-style="italic" fill="#6B6B6B">Data is the new oil, but insights are the fuel that drives innovation.</text>')
    y += FH

    total_h = y
    out = [f'<svg width="{W}" height="{total_h}" viewBox="0 0 {W} {total_h}" xmlns="http://www.w3.org/2000/svg" xmlns:xlink="http://www.w3.org/1999/xlink" role="img" aria-label="Emmanuel Boakye — Data Scientist portfolio">',
           f'<defs>{HEAD}</defs>', f'<rect width="{W}" height="{total_h}" fill="{PAPER}"/>'] + parts + ["</svg>"]
    return "\n".join(out)

def main():
    try:
        stats = fetch_stats(USERNAME)
    except Exception as e:
        print("ERROR fetching stats:", e, file=sys.stderr)
        sys.exit(1)
    svg = build_svg(stats)
    if os.path.dirname(OUT_PATH):
        os.makedirs(os.path.dirname(OUT_PATH), exist_ok=True)
    with open(OUT_PATH, "w") as f:
        f.write(svg)
    print("Wrote " + OUT_PATH + ": repos=%s followers=%s months=%s original=%s%% langs=%s" % (stats["public_repos"], stats["followers"], stats["months"], stats["pct_original"], dict(stats["langs"].most_common(5))))

if __name__ == "__main__":
    main()
